using UnityEngine;
public class Script
{
    public static object Main()
    {
        // 找 AnimalInteractComp 触发喂食
        var animals = Object.FindObjectsOfType<FL.Gameplay.Modules.BigWorld.AnimalController>();
        foreach (var a in animals)
        {
            if (a.NetId == 23)
            {
                // 直接发送喂食请求
                var req = new FL.NetModule.AnimalFeedReq();
                req.AnimalId = a.NetId;
                req.ItemId = "10001"; // 通用食物 ID
                FL.NetModule.NetCmd.AnimalFeed(req, (result) => {
                    UnityEngine.Debug.Log("[TEST] AnimalFeed result: code=" + result.Data?.Code + " animalId=" + result.Data?.AnimalId);
                });
                return "Sent AnimalFeedReq for NetId=23, itemId=10001";
            }
        }
        return "Animal NetId=23 not found";
    }
}
